using ArchStudy.Shared.Dtos;
using ArchStudy.VerticalSlice.Persistence;
using Mediator;

namespace ArchStudy.VerticalSlice.Features;

public sealed record CreateAccountCommand(string Owner) : IRequest<AccountResponse>;

public sealed class CreateAccountHandler(VsDbContext db) : IRequestHandler<CreateAccountCommand, AccountResponse>
{
    public async ValueTask<AccountResponse> Handle(CreateAccountCommand command, CancellationToken ct)
    {
        if (string.IsNullOrWhiteSpace(command.Owner)) throw new ArgumentException("Owner required");

        var record = new AccountRecord
        {
            Id = Guid.NewGuid(),
            Owner = command.Owner,
            Balance = 0m,
            CreatedAt = DateTime.UtcNow,
        };
        db.Accounts.Add(record);
        await db.SaveChangesAsync(ct);
        return new AccountResponse(record.Id, record.Owner, record.Balance, record.CreatedAt);
    }
}

public static class CreateAccountEndpoint
{
    public static void Map(RouteGroupBuilder group) =>
        group.MapPost("/accounts", async Task<IResult> (
            CreateAccountRequest req,
            IRequestHandler<CreateAccountCommand, AccountResponse> handler,
            CancellationToken ct) =>
        {
            var account = await handler.Handle(new CreateAccountCommand(req.Owner), ct);
            return Results.Created($"/vertical-slice/accounts/{account.Id}", account);
        });
}

using ArchStudy.Shared.Dtos;
using ArchStudy.VerticalSlice.Persistence;
using Mediator;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.VerticalSlice.Features;

public sealed record DepositCommand(Guid AccountId, decimal Amount) : IRequest<AccountResponse>;

public sealed class DepositHandler(VsDbContext db) : IRequestHandler<DepositCommand, AccountResponse>
{
    public async ValueTask<AccountResponse> Handle(DepositCommand command, CancellationToken ct)
    {
        if (command.Amount <= 0) throw new ArgumentException("Amount must be positive");

        var account = await db.Accounts.FirstOrDefaultAsync(a => a.Id == command.AccountId, ct)
            ?? throw new KeyNotFoundException("Account not found");

        account.Balance += command.Amount;
        db.Transactions.Add(new TransactionRecord
        {
            Id = Guid.NewGuid(),
            AccountId = account.Id,
            Type = TransactionType.Deposit,
            Amount = command.Amount,
            Timestamp = DateTime.UtcNow,
        });

        await db.SaveChangesAsync(ct);
        return new AccountResponse(account.Id, account.Owner, account.Balance, account.CreatedAt);
    }
}

public static class DepositEndpoint
{
    public static void Map(RouteGroupBuilder group) =>
        group.MapPost("/accounts/{id:guid}/deposits", async Task<IResult> (
            Guid id,
            DepositRequest req,
            IRequestHandler<DepositCommand, AccountResponse> handler,
            CancellationToken ct) =>
            Results.Ok(await handler.Handle(new DepositCommand(id, req.Amount), ct)));
}

using ArchStudy.Shared.Dtos;
using ArchStudy.VerticalSlice.Persistence;
using Mediator;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.VerticalSlice.Features;

public sealed record GetAccountQuery(Guid Id) : IRequest<AccountResponse?>;

public sealed class GetAccountHandler(VsDbContext db) : IRequestHandler<GetAccountQuery, AccountResponse?>
{
    public async ValueTask<AccountResponse?> Handle(GetAccountQuery query, CancellationToken ct)
    {
        var record = await db.Accounts.FirstOrDefaultAsync(a => a.Id == query.Id, ct);
        return record is null ? null : new AccountResponse(record.Id, record.Owner, record.Balance, record.CreatedAt);
    }
}

public static class GetAccountEndpoint
{
    public static void Map(RouteGroupBuilder group) =>
        group.MapGet("/accounts/{id:guid}", async Task<IResult> (
            Guid id,
            IRequestHandler<GetAccountQuery, AccountResponse?> handler,
            CancellationToken ct) =>
        {
            var account = await handler.Handle(new GetAccountQuery(id), ct);
            return account is null ? Results.NotFound() : Results.Ok(account);
        });
}

using ArchStudy.Shared.Dtos;
using ArchStudy.VerticalSlice.Persistence;
using Mediator;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.VerticalSlice.Features;

public sealed record GetStatementQuery(Guid AccountId) : IRequest<IReadOnlyList<TransactionResponse>>;

public sealed class GetStatementHandler(VsDbContext db) : IRequestHandler<GetStatementQuery, IReadOnlyList<TransactionResponse>>
{
    public async ValueTask<IReadOnlyList<TransactionResponse>> Handle(GetStatementQuery query, CancellationToken ct)
    {
        var rows = await db.Transactions
            .Where(t => t.AccountId == query.AccountId)
            .OrderByDescending(t => t.Timestamp)
            .ToListAsync(ct);

        return rows.Select(r => new TransactionResponse(r.Id, r.AccountId, r.Type, r.Amount, r.Timestamp, r.RelatedAccountId)).ToList();
    }
}

public static class GetStatementEndpoint
{
    public static void Map(RouteGroupBuilder group) =>
        group.MapGet("/accounts/{id:guid}/transactions", async Task<IResult> (
            Guid id,
            IRequestHandler<GetStatementQuery, IReadOnlyList<TransactionResponse>> handler,
            CancellationToken ct) =>
            Results.Ok(await handler.Handle(new GetStatementQuery(id), ct)));
}

using ArchStudy.Shared.Dtos;
using ArchStudy.VerticalSlice.Persistence;
using Mediator;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.VerticalSlice.Features;

public sealed record TransferCommand(Guid FromAccountId, Guid ToAccountId, decimal Amount) : IRequest;

public sealed class TransferHandler(VsDbContext db) : IRequestHandler<TransferCommand>
{
    public async ValueTask<Unit> Handle(TransferCommand command, CancellationToken ct)
    {
        if (command.Amount <= 0) throw new ArgumentException("Amount must be positive");
        if (command.FromAccountId == command.ToAccountId) throw new ArgumentException("Accounts must differ");

        var from = await db.Accounts.FirstOrDefaultAsync(a => a.Id == command.FromAccountId, ct)
            ?? throw new KeyNotFoundException("Source account not found");
        var to = await db.Accounts.FirstOrDefaultAsync(a => a.Id == command.ToAccountId, ct)
            ?? throw new KeyNotFoundException("Destination account not found");
        if (from.Balance < command.Amount) throw new InvalidOperationException("Insufficient funds");

        from.Balance -= command.Amount;
        to.Balance += command.Amount;
        var now = DateTime.UtcNow;
        db.Transactions.Add(new TransactionRecord { Id = Guid.NewGuid(), AccountId = from.Id, Type = TransactionType.TransferOut, Amount = command.Amount, Timestamp = now, RelatedAccountId = to.Id });
        db.Transactions.Add(new TransactionRecord { Id = Guid.NewGuid(), AccountId = to.Id, Type = TransactionType.TransferIn, Amount = command.Amount, Timestamp = now, RelatedAccountId = from.Id });
        await db.SaveChangesAsync(ct);
        return Unit.Value;
    }
}

public static class TransferEndpoint
{
    public static void Map(RouteGroupBuilder group) =>
        group.MapPost("/transfers", async Task<IResult> (
            TransferRequest req,
            IRequestHandler<TransferCommand> handler,
            CancellationToken ct) =>
        {
            await handler.Handle(new TransferCommand(req.FromAccountId, req.ToAccountId, req.Amount), ct);
            return Results.NoContent();
        });
}

